    .skills-grid { grid-template-columns: 1fr 1fr; }
    .hero-stats { gap: 16px; }
    .stat-number { font-size: 22px; }
    .section-title { font-size: 30px; }
    .footer-grid { grid-template-columns: 1fr; }
    .footer-bottom { flex-direction: column; gap: 12px; }
}

